DROP TABLE IF EXISTS `slr_rule_cond`;
CREATE TABLE `slr_rule_cond`
(
    `id`                     bigint UNSIGNED                                        NOT NULL AUTO_INCREMENT COMMENT '自增主键ID',
    `cond_code`              varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '条件编号',
    `cond_type`              varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '条件类型',
    `window_value`           bigint UNSIGNED                                        NULL DEFAULT NULL COMMENT '窗口值',
    `window_unit`            varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '窗口单位',
    `threshold`              bigint                                                 NULL DEFAULT NULL COMMENT '阈值',
    `threshold_scale_factor` bigint NULL DEFAULT NULL COMMENT '阈值缩放因子',
    `cross_history`          bit(1)                                                 NULL DEFAULT NULL COMMENT '条件类型',
    `cross_history_timeline` datetime                                               NULL DEFAULT NULL COMMENT '跨历史时间点',
    `rule_code`              bigint UNSIGNED                                        NULL DEFAULT NULL COMMENT '规则编号',
    `event_code`             varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '事件编号',
    `creator`                varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '创建用户',
    `updater`                varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '更新用户',
    `create_time`            datetime                                               NULL DEFAULT NULL COMMENT '创建时间',
    `update_time`            datetime                                               NULL DEFAULT NULL COMMENT '创建时间',
    PRIMARY KEY (`id`) USING BTREE,
    UNIQUE INDEX `uk_cond_code` (`cond_code` ASC) USING BTREE
) ENGINE = InnoDB
  AUTO_INCREMENT = 138
  CHARACTER SET = utf8mb4
  COLLATE = utf8mb4_bin COMMENT = '风控规则条件'
  ROW_FORMAT = DYNAMIC;

