-- ----------------------------
-- Table structure for slr_rule_time_range
-- ----------------------------
DROP TABLE IF EXISTS `slr_rule_time_range`;
CREATE TABLE `slr_rule_time_range`
(
    `id`                 bigint UNSIGNED                                        NOT NULL AUTO_INCREMENT COMMENT '自增主键ID',
    `type`               varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '类型，如 DAILY,WEEKLY,MONTHLY,YEARLY_MONTH,YEARLY_DATE_RANGE',
    `start_time`         time                                                   NULL DEFAULT NULL COMMENT '开始时间',
    `end_time`           time                                                   NULL DEFAULT NULL COMMENT '结束时间',
    `days_of_week`       varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '适用的星期天，如 MONDAY,WEDNESDAY,FRIDAY',
    `start_day_of_month` int                                                    NULL DEFAULT NULL COMMENT '每月适用开始日期',
    `end_day_of_month`   int                                                    NULL DEFAULT NULL COMMENT '每月适用结束日期',
    `start_month`        int                                                    NULL DEFAULT NULL COMMENT '每年适用开始月份',
    `end_month`          int                                                    NULL DEFAULT NULL COMMENT '每年适用结束月份',
    `start_yearly_date`  varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '每年固定开始日期 (MM-DD)',
    `end_yearly_date`    varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '每年固定结束日期 (MM-DD)',
    `cond_code`          varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '条件编号',
    `creator`            varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '创建用户',
    `updater`            varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '更新用户',
    `create_time`        datetime                                               NULL DEFAULT NULL COMMENT '创建时间',
    `update_time`        datetime                                               NULL DEFAULT NULL COMMENT '更新时间',
    PRIMARY KEY (`id`) USING BTREE,
    UNIQUE INDEX `uk_cond_code` (`cond_code` ASC) USING BTREE
) ENGINE = InnoDB
  AUTO_INCREMENT = 22
  CHARACTER SET = utf8mb4
  COLLATE = utf8mb4_bin COMMENT = '风控规则条件时间范围'
  ROW_FORMAT = DYNAMIC;

